create table pis_storitve_pos.task (
    task_id          number(18, 0) default pis_storitve_pos.task_seq.nextval,
    status           varchar2(100 char) not null enable,
    repeat_count     number(18, 0) not null enable,
    context          varchar2(100 char) not null enable,
    context_id       varchar2(100 char),
    next_run_time    timestamp(6),
    lock_time        timestamp(6),
    data             clob not null enable,
    queue            varchar2(100 char) not null enable,
    unique_flag      number(1, 0) not null enable,
    force_processing number(1, 0) not null enable,
    error            clob,
    created          timestamp(6) not null enable,
    updated          timestamp(6) not null enable
);

alter table pis_storitve_pos.task
    add constraint pk_task primary key ( task_id )
        using index enable;


